import { buildMatchFn } from "../../_lib/buildMatchFn.mjs";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.mjs";

const matchOrdinalNumberPattern = /^(\d+)(-?(械|褟|泄|芯械|褜械|邪褟|褜褟|褘泄|芯泄|懈泄|褘泄))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((写芯 )?薪\.?\s?褝\.?)/i,
  abbreviated: /^((写芯 )?薪\.?\s?褝\.?)/i,
  wide: /^(写芯 薪邪褕械泄 褝褉褘|薪邪褕械泄 褝褉褘|薪邪褕邪 褝褉邪)/i,
};
const parseEraPatterns = {
  any: [/^写/i, /^薪/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[褘芯懈]?泄?)? 泻胁.?/i,
  wide: /^[1234](-?[褘芯懈]?泄?)? 泻胁邪褉褌邪谢/i,
};

const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[褟褎屑邪懈褋芯薪写]/i,
  abbreviated:
    /^(褟薪胁|褎械胁|屑邪褉褌?|邪锌褉|屑邪[泄褟]|懈褞薪[褜褟]?|懈褞谢[褜褟]?|邪胁谐|褋械薪褌?|芯泻褌|薪芯褟斜?|写械泻)\.?/i,
  wide: /^(褟薪胁邪褉[褜褟]|褎械胁褉邪谢[褜褟]|屑邪褉褌邪?|邪锌褉械谢[褜褟]|屑邪[泄褟]|懈褞薪[褜褟]|懈褞谢[褜褟]|邪胁谐褍褋褌邪?|褋械薪褌褟斜褉[褜褟]|芯泻褌褟斜褉[褜褟]|芯泻褌褟斜褉[褜褟]|薪芯褟斜褉[褜褟]|写械泻邪斜褉[褜褟])/i,
};

const parseMonthPatterns = {
  narrow: [
    /^褟/i,
    /^褎/i,
    /^屑/i,
    /^邪/i,
    /^屑/i,
    /^懈/i,
    /^懈/i,
    /^邪/i,
    /^褋/i,
    /^芯/i,
    /^薪/i,
    /^褟/i,
  ],

  any: [
    /^褟/i,
    /^褎/i,
    /^屑邪褉/i,
    /^邪锌/i,
    /^屑邪[泄褟]/i,
    /^懈褞薪/i,
    /^懈褞谢/i,
    /^邪胁/i,
    /^褋/i,
    /^芯/i,
    /^薪/i,
    /^写/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[胁锌褋褔]/i,
  short: /^(胁褋|胁芯|锌薪|锌芯|胁褌|褋褉|褔褌|褔械|锌褌|锌褟|褋斜|褋褍)\.?/i,
  abbreviated: /^(胁褋泻|胁芯褋|锌薪写|锌芯薪|胁褌褉|胁褌芯|褋褉写|褋褉械|褔褌胁|褔械褌|锌褌薪|锌褟褌|褋褍斜).?/i,
  wide: /^(胁芯褋泻褉械褋械薪褜[械褟]|锌芯薪械写械谢褜薪懈泻邪?|胁褌芯褉薪懈泻邪?|褋褉械写[邪褘]|褔械褌胁械褉谐邪?|锌褟褌薪懈褑[邪褘]|褋褍斜斜芯褌[邪褘])/i,
};

const parseDayPatterns = {
  narrow: [/^胁/i, /^锌/i, /^胁/i, /^褋/i, /^褔/i, /^锌/i, /^褋/i],
  any: [/^胁[芯褋]/i, /^锌[芯薪]/i, /^胁/i, /^褋褉/i, /^褔/i, /^锌[褟褌]/i, /^褋[褍斜]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([写锌]锌|锌芯谢薪\.?|锌芯谢写\.?|褍褌褉[芯邪]|写械薪褜|写薪褟|胁械褔\.?|薪芯褔[褜懈])/i,
  abbreviated: /^([写锌]锌|锌芯谢薪\.?|锌芯谢写\.?|褍褌褉[芯邪]|写械薪褜|写薪褟|胁械褔\.?|薪芯褔[褜懈])/i,
  wide: /^([写锌]锌|锌芯谢薪芯褔褜|锌芯谢写械薪褜|褍褌褉[芯邪]|写械薪褜|写薪褟|胁械褔械褉邪?|薪芯褔[褜懈])/i,
};

const parseDayPeriodPatterns = {
  any: {
    am: /^写锌/i,
    pm: /^锌锌/i,
    midnight: /^锌芯谢薪/i,
    noon: /^锌芯谢写/i,
    morning: /^褍/i,
    afternoon: /^写[械薪]/i,
    evening: /^胁/i,
    night: /^薪/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
